import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { orderAPI, walletAPI } from '../services/api';
import './Checkout.css';

// ─── Load Razorpay script dynamically ────────────────────────────────────────
const loadRazorpayScript = () =>
  new Promise((resolve) => {
    if (document.getElementById('razorpay-script')) { resolve(true); return; }
    const script = document.createElement('script');
    script.id  = 'razorpay-script';
    script.src = 'https://checkout.razorpay.com/v1/checkout.js';
    script.onload  = () => resolve(true);
    script.onerror = () => resolve(false);
    document.body.appendChild(script);
  });

// ✅ Matches backend modeOfPayment values exactly
const PAYMENT_METHODS = [
  { value: 'COD',         label: '💵 Cash on Delivery' },
  { value: 'WALLET',      label: '💰 Wallet' },
  { value: 'UPI',         label: '📱 UPI' },
  { value: 'CREDIT_CARD', label: '💳 Credit Card' },
  { value: 'DEBIT_CARD',  label: '🏦 Debit Card' },
  { value: 'NET_BANKING', label: '🌐 Net Banking' },
];

// Payment methods that go through Razorpay
const RAZORPAY_METHODS = ['UPI', 'CREDIT_CARD', 'DEBIT_CARD', 'NET_BANKING'];

export default function Checkout() {
  const { cartItems, totalPrice, totalItems, clearCart } = useCart();
  const { user } = useAuth();
  const toast    = useToast();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    fullName:      user?.fullName || '',
    mobileNumber:  '',
    flatNumber:    '',
    city:          '',
    state:         '',
    pincode:       '',
    modeOfPayment: 'COD',
  });
  const [placing,       setPlacing]       = useState(false);
  const [errors,        setErrors]        = useState({});
  const [walletBalance, setWalletBalance] = useState(null);
  const [walletLoading, setWalletLoading] = useState(false);

  // ── Fetch wallet balance on mount ──────────────────────────────────────────
  useEffect(() => {
    const fetchWallet = async () => {
      setWalletLoading(true);
      try {
        const res = await walletAPI.getMyWallet();
        setWalletBalance(res.data?.balance ?? 0);
      } catch {
        setWalletBalance(0);
      } finally {
        setWalletLoading(false);
      }
    };
    fetchWallet();
  }, []);

  // Redirect if cart is empty
  if (!cartItems || cartItems.length === 0) {
    return (
      <div className="checkout-page">
        <div className="checkout-empty">
          <div className="empty-icon">🛒</div>
          <h2>Your cart is empty</h2>
          <p>Add some books before checking out.</p>
          <Link to="/books" className="btn-primary">Browse Books</Link>
        </div>
      </div>
    );
  }

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors(prev => ({ ...prev, [name]: '' }));
  };

  const validate = () => {
    const e = {};
    if (!form.fullName.trim())     e.fullName     = 'Full name is required';
    if (!form.mobileNumber.trim()) e.mobileNumber = 'Mobile number is required';
    else if (!/^\d{10}$/.test(form.mobileNumber.trim())) e.mobileNumber = 'Enter a valid 10-digit number';
    if (!form.flatNumber.trim())   e.flatNumber   = 'Flat/House number is required';
    if (!form.city.trim())         e.city         = 'City is required';
    if (!form.state.trim())        e.state        = 'State is required';
    if (!form.pincode.trim())      e.pincode      = 'Pincode is required';
    else if (!/^\d{6}$/.test(form.pincode.trim())) e.pincode = 'Enter a valid 6-digit pincode';
    return e;
  };

  // ── Build order payload ─────────────────────────────────────────────────────
  const buildPayload = (modeOfPayment) => ({
    fullName:      form.fullName.trim(),
    mobileNumber:  form.mobileNumber.trim(),
    flatNumber:    form.flatNumber.trim(),
    city:          form.city.trim(),
    state:         form.state.trim(),
    pincode:       form.pincode.trim(),
    modeOfPayment,
    items: cartItems.map(item => ({
      bookId:     item.bookId,
      bookTitle:  item.bookTitle,
      bookAuthor: item.bookAuthor || '',
      price:      item.price,
      quantity:   item.quantity,
    })),
  });

  // ── Place order after payment is confirmed ──────────────────────────────────
  const finalizeOrder = async (modeOfPayment) => {
    const payload = buildPayload(modeOfPayment);
    await orderAPI.placeOrder(payload);
    await clearCart();
    toast.success('Order placed successfully! 🎉');
    navigate('/orders');
  };

  // ── COD flow ────────────────────────────────────────────────────────────────
  const handleCOD = async () => {
    setPlacing(true);
    try {
      await finalizeOrder('COD');
    } catch (err) {
      const msg = err.response?.data?.message || 'Failed to place order. Please try again.';
      toast.error(msg);
    } finally {
      setPlacing(false);
    }
  };

  // ── Wallet flow ─────────────────────────────────────────────────────────────
  const handleWallet = async () => {
    if (walletBalance === null) { toast.error('Wallet balance not loaded yet'); return; }
    if (walletBalance < totalPrice) {
      toast.error(`Insufficient wallet balance. Available: ₹${walletBalance.toFixed(2)}`);
      return;
    }

    setPlacing(true);
    try {
      // Deduct from wallet first
      await walletAPI.deductMoney({
        amount:      totalPrice,
        description: `Order payment for ${totalItems} item(s)`,
      });
      // Then place the order
      await finalizeOrder('WALLET');
    } catch (err) {
      const msg = err.response?.data?.message || err.response?.data?.error || 'Payment failed. Please try again.';
      toast.error(msg);
    } finally {
      setPlacing(false);
    }
  };

  // ── Razorpay flow (UPI / Cards / Net Banking) ───────────────────────────────
  const handleRazorpay = async (modeOfPayment) => {
    setPlacing(true);
    try {
      // Step 1 — Load Razorpay SDK
      const scriptLoaded = await loadRazorpayScript();
      if (!scriptLoaded) {
        toast.error('Failed to load Razorpay. Check your internet connection.');
        setPlacing(false);
        return;
      }

      // Step 2 — Create Razorpay order on backend
      const orderRes = await walletAPI.createRazorpayOrder(totalPrice);
      const { orderId, keyId, currency } = orderRes.data;

      // Step 3 — Map our internal method → Razorpay method hint
      const methodMap = {
        UPI:         'upi',
        CREDIT_CARD: 'card',
        DEBIT_CARD:  'card',
        NET_BANKING: 'netbanking',
      };

      const options = {
        key:         keyId,
        amount:      totalPrice * 100, // paise
        currency:    currency || 'INR',
        name:        'BookNest',
        description: `Payment for ${totalItems} book(s)`,
        order_id:    orderId,
        theme:       { color: '#c9a84c' },
        method:      { [methodMap[modeOfPayment]]: true },

        handler: async (response) => {
          try {
            // Step 4 — Verify signature on backend
            await walletAPI.verifyRazorpayPayment({
              razorpayOrderId:   response.razorpay_order_id,
              razorpayPaymentId: response.razorpay_payment_id,
              razorpaySignature: response.razorpay_signature,
              amount:            totalPrice,
            });
            // Step 5 — Place order
            await finalizeOrder(modeOfPayment);
          } catch (err) {
            toast.error(err.response?.data?.error || 'Payment verified but order failed. Contact support.');
          } finally {
            setPlacing(false);
          }
        },

        modal: {
          ondismiss: () => {
            toast.error('Payment cancelled.');
            setPlacing(false);
          },
        },

        prefill: {
          name:    form.fullName,
          contact: form.mobileNumber,
        },
      };

      const rzp = new window.Razorpay(options);
      rzp.on('payment.failed', (response) => {
        toast.error(`Payment failed: ${response.error?.description || 'Unknown error'}`);
        setPlacing(false);
      });
      rzp.open();

    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to initiate payment. Please try again.');
      setPlacing(false);
    }
  };

  // ── Main handler ─────────────────────────────────────────────────────────────
  const handlePlaceOrder = async () => {
    const e = validate();
    if (Object.keys(e).length > 0) {
      setErrors(e);
      toast.error('Please fill all required fields correctly');
      return;
    }

    if (form.modeOfPayment === 'COD')              return handleCOD();
    if (form.modeOfPayment === 'WALLET')            return handleWallet();
    if (RAZORPAY_METHODS.includes(form.modeOfPayment)) return handleRazorpay(form.modeOfPayment);
  };

  // ── Wallet balance display ───────────────────────────────────────────────────
  const isWalletInsufficient =
    form.modeOfPayment === 'WALLET' &&
    walletBalance !== null &&
    walletBalance < totalPrice;

  return (
    <div className="checkout-page">
      <div className="checkout-container">

        {/* ── Left: Form ───────────────────────────────────────── */}
        <div className="checkout-form-section">

          {/* Delivery Address */}
          <div className="checkout-card">
            <h2 className="section-title">📦 Delivery Address</h2>

            <div className="form-group">
              <label>Full Name *</label>
              <input
                type="text"
                name="fullName"
                value={form.fullName}
                onChange={handleChange}
                placeholder="Enter your full name"
                className={errors.fullName ? 'input-error' : ''}
              />
              {errors.fullName && <span className="error-msg">{errors.fullName}</span>}
            </div>

            <div className="form-group">
              <label>Mobile Number *</label>
              <input
                type="tel"
                name="mobileNumber"
                value={form.mobileNumber}
                onChange={handleChange}
                placeholder="10-digit mobile number"
                maxLength={10}
                className={errors.mobileNumber ? 'input-error' : ''}
              />
              {errors.mobileNumber && <span className="error-msg">{errors.mobileNumber}</span>}
            </div>

            <div className="form-group">
              <label>Flat / House No. / Building *</label>
              <input
                type="text"
                name="flatNumber"
                value={form.flatNumber}
                onChange={handleChange}
                placeholder="House no., Building, Street, Area"
                className={errors.flatNumber ? 'input-error' : ''}
              />
              {errors.flatNumber && <span className="error-msg">{errors.flatNumber}</span>}
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>City *</label>
                <input
                  type="text"
                  name="city"
                  value={form.city}
                  onChange={handleChange}
                  placeholder="City"
                  className={errors.city ? 'input-error' : ''}
                />
                {errors.city && <span className="error-msg">{errors.city}</span>}
              </div>

              <div className="form-group">
                <label>State *</label>
                <input
                  type="text"
                  name="state"
                  value={form.state}
                  onChange={handleChange}
                  placeholder="State"
                  className={errors.state ? 'input-error' : ''}
                />
                {errors.state && <span className="error-msg">{errors.state}</span>}
              </div>

              <div className="form-group">
                <label>Pincode *</label>
                <input
                  type="text"
                  name="pincode"
                  value={form.pincode}
                  onChange={handleChange}
                  placeholder="6-digit pincode"
                  maxLength={6}
                  className={errors.pincode ? 'input-error' : ''}
                />
                {errors.pincode && <span className="error-msg">{errors.pincode}</span>}
              </div>
            </div>
          </div>

          {/* Payment Method */}
          <div className="checkout-card">
            <h2 className="section-title">💳 Payment Method</h2>
            <div className="payment-options">
              {PAYMENT_METHODS.map(pm => (
                <label
                  key={pm.value}
                  className={`payment-option ${form.modeOfPayment === pm.value ? 'selected' : ''}`}
                >
                  <input
                    type="radio"
                    name="modeOfPayment"
                    value={pm.value}
                    checked={form.modeOfPayment === pm.value}
                    onChange={handleChange}
                  />
                  <span>{pm.label}</span>
                  {/* Wallet balance badge */}
                  {pm.value === 'WALLET' && (
                    <span style={{
                      marginLeft: 'auto',
                      fontSize: '0.8rem',
                      color: walletLoading ? '#888' :
                             (walletBalance !== null && walletBalance < totalPrice ? '#ef4444' : '#10b981'),
                      fontWeight: 600,
                    }}>
                      {walletLoading
                        ? 'Loading…'
                        : walletBalance !== null
                          ? `Bal: ₹${walletBalance.toFixed(2)}`
                          : ''}
                    </span>
                  )}
                  {/* Razorpay badge for online methods */}
                  {RAZORPAY_METHODS.includes(pm.value) && (
                    <span style={{
                      marginLeft: 'auto',
                      fontSize: '0.72rem',
                      color: '#888',
                    }}>
                      via Razorpay
                    </span>
                  )}
                </label>
              ))}
            </div>

            {/* Wallet insufficient warning */}
            {isWalletInsufficient && (
              <div style={{
                marginTop: 10,
                padding: '10px 14px',
                background: 'rgba(239,68,68,0.12)',
                borderRadius: 8,
                color: '#ef4444',
                fontSize: '0.85rem',
              }}>
                ⚠️ Insufficient wallet balance. You need ₹{totalPrice?.toFixed(2)} but have ₹{walletBalance?.toFixed(2)}.
                {' '}<Link to="/wallet" style={{ color: '#c9a84c', textDecoration: 'underline' }}>Add money →</Link>
              </div>
            )}

            {/* Razorpay info */}
            {RAZORPAY_METHODS.includes(form.modeOfPayment) && (
              <div style={{
                marginTop: 10,
                padding: '10px 14px',
                background: 'rgba(201,168,76,0.1)',
                borderRadius: 8,
                fontSize: '0.82rem',
                color: '#aaa',
              }}>
                🔒 You'll be redirected to Razorpay's secure payment page to complete the payment.
              </div>
            )}
          </div>
        </div>

        {/* ── Right: Order Summary ─────────────────────────────── */}
        <div className="checkout-summary-section">
          <div className="checkout-card summary-card">
            <h2 className="section-title">🛒 Order Summary</h2>

            <div className="summary-items">
              {cartItems.map((item) => (
                <div key={item.itemId} className="summary-item">
                  <div className="summary-item-info">
                    <span className="summary-item-title">{item.bookTitle}</span>
                    <span className="summary-item-qty">x{item.quantity}</span>
                  </div>
                  <span className="summary-item-price">
                    ₹{(item.price * item.quantity).toFixed(2)}
                  </span>
                </div>
              ))}
            </div>

            <div className="summary-divider" />

            <div className="summary-row">
              <span>Items ({totalItems})</span>
              <span>₹{totalPrice?.toFixed(2)}</span>
            </div>
            <div className="summary-row">
              <span>Delivery</span>
              <span className="free-tag">FREE</span>
            </div>

            <div className="summary-divider" />

            <div className="summary-row summary-total">
              <span>Total</span>
              <strong>₹{totalPrice?.toFixed(2)}</strong>
            </div>

            <button
              className="place-order-btn"
              onClick={handlePlaceOrder}
              disabled={placing || isWalletInsufficient}
            >
              {placing
                ? (form.modeOfPayment === 'WALLET'
                    ? 'Deducting from Wallet…'
                    : RAZORPAY_METHODS.includes(form.modeOfPayment)
                      ? 'Opening Razorpay…'
                      : 'Placing Order…')
                : '✅ Place Order'}
            </button>

            <Link to="/cart" className="back-to-cart">
              ← Back to Cart
            </Link>
          </div>
        </div>

      </div>
    </div>
  );
}
